// Extract deal ID from webhook payload
const input = $input.first().json;
const body = input.body || input;
const dealId = body.dealId || body.deal_id || body.id || input.dealId || input.deal_id || input.id;

if (!dealId) {
  throw new Error('No dealId provided in webhook payload. Keys received: ' + JSON.stringify(Object.keys(input)));
}

return [{ json: { dealId: String(dealId) } }];

// Combine deal data into context object for Claude
// Notes fetching skipped for MVP — can be added later
const deal = $input.first().json;
const dealId = $('Extract Deal ID').first().json.dealId;

const dealData = {
  deal_id: deal.id || dealId,
  deal_name: deal.properties?.dealname || 'Unknown',
  deal_stage: deal.properties?.dealstage || 'Unknown',
  amount: deal.properties?.amount || 'Not set',
  existing_meddpicc: {
    metrics: deal.properties?.meddpicc_metrics || 'No data',
    economic_buyer: deal.properties?.meddpicc_economic_buyer || 'No data',
    decision_criteria: deal.properties?.meddpicc_decision_criteria || 'No data',
    decision_process: deal.properties?.meddpicc_decision_process || 'No data',
    paper_process: deal.properties?.meddpicc_paper_process || 'No data',
    pain: deal.properties?.meddpicc_pain || 'No data',
    champion: deal.properties?.meddpicc_champion || 'No data',
    competition: deal.properties?.meddpicc_competition || 'No data'
  },
  notes_count: 0,
  current_health_score: deal.properties?.deal_health_score || 'Not scored'
};

return [{
  json: {
    dealId: deal.id || dealId,
    dealStage: deal.properties?.dealstage || 'Unknown',
    dealData: dealData
  }
}];

// Parse Claude MEDDPICC response
const response = $input.first().json;
const dealId = $('Build Deal Context').first().json.dealId;

let scoring;
try {
  const content = response.content[0].text;
  const jsonStr = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  scoring = JSON.parse(jsonStr);
} catch (e) {
  throw new Error('Failed to parse Claude MEDDPICC response: ' + e.message);
}

// Build HubSpot properties update
const properties = {
  meddpicc_metrics: `[${scoring.meddpicc_metrics.score}/5] ${scoring.meddpicc_metrics.evidence}`,
  meddpicc_economic_buyer: `[${scoring.meddpicc_economic_buyer.score}/5] ${scoring.meddpicc_economic_buyer.evidence}`,
  meddpicc_decision_criteria: `[${scoring.meddpicc_decision_criteria.score}/5] ${scoring.meddpicc_decision_criteria.evidence}`,
  meddpicc_decision_process: `[${scoring.meddpicc_decision_process.score}/5] ${scoring.meddpicc_decision_process.evidence}`,
  meddpicc_paper_process: `[${scoring.meddpicc_paper_process.score}/5] ${scoring.meddpicc_paper_process.evidence}`,
  meddpicc_pain: `[${scoring.meddpicc_pain.score}/5] ${scoring.meddpicc_pain.evidence}`,
  meddpicc_champion: `[${scoring.meddpicc_champion.score}/5] ${scoring.meddpicc_champion.evidence}`,
  meddpicc_competition: `[${scoring.meddpicc_competition.score}/5] ${scoring.meddpicc_competition.evidence}`,
  deal_health_score: String(scoring.deal_health_score)
};

return [{
  json: {
    dealId,
    properties,
    overall_score: scoring.overall_score,
    deal_health_score: scoring.deal_health_score,
    top_gaps: scoring.top_gaps,
    recommended_actions: scoring.recommended_actions
  }
}];
